  1→"use client";
  2→
  3→import { useState } from "react";
  4→import { Button } from "@/components/ui/button";
  5→import { Input } from "@/components/ui/input";
  6→import { Label } from "@/components/ui/label";
  7→import {
  8→  Dialog,
  9→  DialogContent,
 10→  DialogDescription,
 11→  DialogFooter,
 12→  DialogHeader,
 13→  DialogTitle,
 14→} from "@/components/ui/dialog";
 15→import { useToast } from "@/components/ui/use-toast";
 16→
 17→interface InvestmentDepositModalProps {
 18→  investmentId: string;
 19→  investmentName: string;
 20→  open: boolean;
 21→  onOpenChange: (open: boolean) => void;
 22→  onSuccess: () => void;
 23→}
 24→
 25→export function InvestmentDepositModal({
 26→  investmentId,
 27→  investmentName,
 28→  open,
 29→  onOpenChange,
 30→  onSuccess,
 31→}: InvestmentDepositModalProps) {
 32→  const { toast } = useToast();
 33→  const [loading, setLoading] = useState(false);
 34→  const [amount, setAmount] = useState("");
 35→  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);
 36→  const [notes, setNotes] = useState("");
 37→
 38→  function resetForm() {
 39→    setAmount("");
 40→    setDate(new Date().toISOString().split("T")[0]);
 41→    setNotes("");
 42→  }
 43→
 44→  function handleOpenChange(newOpen: boolean) {
 45→    if (!newOpen) {
 46→      resetForm();
 47→    }
 48→    onOpenChange(newOpen);
 49→  }
 50→
 51→  async function handleSubmit(e: React.FormEvent) {
 52→    e.preventDefault();
 53→
 54→    const parsedAmount = parseFloat(amount);
 55→    if (!amount || isNaN(parsedAmount) || parsedAmount <= 0) {
 56→      toast({
 57→        title: "Erro",
 58→        description: "Informe um valor valido para o aporte",
 59→        variant: "destructive",
 60→      });
 61→      return;
 62→    }
 63→
 64→    setLoading(true);
 65→
 66→    try {
 67→      const res = await fetch(`/api/investments/${investmentId}/deposit`, {
 68→        method: "POST",
 69→        headers: { "Content-Type": "application/json" },
 70→        body: JSON.stringify({
 71→          amount: parsedAmount,
 72→          date,
 73→          notes: notes.trim() || null,
 74→        }),
 75→      });
 76→
 77→      if (!res.ok) {
 78→        const error = await res.json().catch(() => ({}));
 79→        throw new Error(error.error || "Erro ao registrar aporte");
 80→      }
 81→
 82→      toast({
 83→        title: "Sucesso",
 84→        description: "Aporte registrado com sucesso",
 85→      });
 86→
 87→      resetForm();
 88→      onOpenChange(false);
 89→      onSuccess();
 90→    } catch (error) {
 91→      toast({
 92→        title: "Erro",
 93→        description:
 94→          error instanceof Error ? error.message : "Erro ao registrar aporte",
 95→        variant: "destructive",
 96→      });
 97→    } finally {
 98→      setLoading(false);
 99→    }
100→  }
101→
102→  return (
103→    <Dialog open={open} onOpenChange={handleOpenChange}>
104→      <DialogContent className="sm:max-w-[425px]">
105→        <DialogHeader>
106→          <DialogTitle>Registrar Aporte</DialogTitle>
107→          <DialogDescription>
108→            Adicione um novo aporte ao investimento{" "}
109→            <span className="font-medium">{investmentName}</span>
110→          </DialogDescription>
111→        </DialogHeader>
112→
113→        <form onSubmit={handleSubmit} className="space-y-4">
114→          <div className="space-y-2">
115→            <Label htmlFor="deposit-amount">Valor *</Label>
116→            <Input
117→              id="deposit-amount"
118→              type="number"
119→              step="0.01"
120→              min="0.01"
121→              value={amount}
122→              onChange={(e) => setAmount(e.target.value)}
123→              placeholder="0,00"
124→              autoFocus
125→            />
126→          </div>
127→
128→          <div className="space-y-2">
129→            <Label htmlFor="deposit-date">Data</Label>
130→            <Input
131→              id="deposit-date"
132→              type="date"
133→              value={date}
134→              onChange={(e) => setDate(e.target.value)}
135→            />
136→          </div>
137→
138→          <div className="space-y-2">
139→            <Label htmlFor="deposit-notes">Notas (opcional)</Label>
140→            <Input
141→              id="deposit-notes"
142→              value={notes}
143→              onChange={(e) => setNotes(e.target.value)}
144→              placeholder="Ex: Aporte mensal, bonus, etc."
145→            />
146→          </div>
147→
148→          <DialogFooter className="gap-2 sm:gap-0">
149→            <Button
150→              type="button"
151→              variant="outline"
152→              onClick={() => handleOpenChange(false)}
153→              disabled={loading}
154→            >
155→              Cancelar
156→            </Button>
157→            <Button type="submit" disabled={loading}>
158→              {loading ? "Registrando..." : "Registrar Aporte"}
159→            </Button>
160→          </DialogFooter>
161→        </form>
162→      </DialogContent>
163→    </Dialog>
164→  );
165→}
