124→              type="date"
125→              value={date}
126→              onChange={(e) => setDate(e.target.value)}
127→            />
128→          </div>
129→
130→          <div className="space-y-2">
131→            <Label htmlFor="reg-origin">Origem / Banco</Label>
132→            <Input
