 5→export async function GET() {
 6→  try {
 7→    const userId = await getAuthenticatedUserId();
 8→
 9→    const categories = await prisma.category.findMany({
10→      where: { userId },
11→      orderBy: {
12→        name: "asc",
13→      },
14→    });
15→
16→    return NextResponse.json(categories);
17→  } catch (error) {
18→    if (error instanceof Error && error.message === "Unauthorized") {
19→      return unauthorizedResponse();
20→    }
21→    console.error("Error fetching categories:", error);
22→    return NextResponse.json(
23→      { error: "Erro ao buscar categorias" },
24→      { status: 500 }
25→    );
26→  }
27→}
