29→export async function POST(request: NextRequest) {
30→  try {
31→    const userId = await getAuthenticatedUserId();
32→
33→    const body = await request.json();
34→    const { name, color, icon } = body;
35→
36→    const category = await prisma.category.create({
37→      data: {
38→        name,
39→        color,
40→        icon,
41→        userId,
42→      },
43→    });
44→
45→    return NextResponse.json(category, { status: 201 });
46→  } catch (error) {
47→    if (error instanceof Error && error.message === "Unauthorized") {
48→      return unauthorizedResponse();
49→    }
50→    console.error("Error creating category:", error);

