 55→export function BillPaymentModal({
 56→  isOpen,
 57→  onClose,
 58→  onSuccess,
 59→  bill,
 60→}: BillPaymentModalProps) {
 61→  const { toast } = useToast();
 62→  const [loading, setLoading] = useState(false);
 63→
 64→  // Payment mode: full or partial
 65→  const [paymentMode, setPaymentMode] = useState<PaymentMode>("full");
 66→
 67→  // Partial payment type: rollover or finance
 68→  const [partialType, setPartialType] = useState<PartialPaymentType>("rollover");
 69→
 70→  // Amount to pay now (used for both rollover and finance entry)
 71→  const [amountToPay, setAmountToPay] = useState("");
 72→
 73→  // Number of installments for financing
 74→  const [installments, setInstallments] = useState("2");
 75→
 76→  // Interest rate (optional)
 77→  const [interestRate, setInterestRate] = useState("");
 78→
 79→  // Derived values
 80→  const parsedAmountToPay = useMemo(() => {
 81→    const val = parseFloat(amountToPay);
 82→    return isNaN(val) ? 0 : val;
 83→  }, [amountToPay]);
 84→
 85→  const remainingAmount = useMemo(() => {
 86→    return Math.max(0, bill.total - parsedAmountToPay);
 87→  }, [bill.total, parsedAmountToPay]);
 88→
 89→  const installmentCount = useMemo(() => {
 90→    return parseInt(installments) || 2;
 91→  }, [installments]);
 92→
 93→  const installmentValue = useMemo(() => {
 94→    if (installmentCount <= 0) return 0;
 95→    return remainingAmount / installmentCount;
 96→  }, [remainingAmount, installmentCount]);
 97→
 98→  const monthLabel = useMemo(() => {
 99→    return `${MONTH_NAMES[bill.month - 1]}/${bill.year}`;
100→  }, [bill.month, bill.year]);
101→
102→  // Reset form when modal opens
103→  useEffect(() => {
104→    if (isOpen) {
105→      setPaymentMode("full");
106→      setPartialType("rollover");
107→      setAmountToPay("");
108→      setInstallments("2");
109→      setInterestRate("");
110→    }
111→  }, [isOpen]);
112→
113→  // Update default amount when switching modes
114→  useEffect(() => {
115→    if (paymentMode === "partial" && !amountToPay) {
116→      // Default to paying 80% when switching to partial
117→      setAmountToPay((bill.total * 0.8).toFixed(2));
