  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→// GET - List deleted transactions
  6→export async function GET() {
  7→  try {
  8→    const userId = await getAuthenticatedUserId();
  9→
 10→    const transactions = await prisma.transaction.findMany({
 11→      where: {
 12→        userId,
 13→        deletedAt: { not: null },
 14→      },
 15→      include: {
 16→        category: true,
 17→        installment: true,
 18→      },
 19→      orderBy: {
 20→        deletedAt: "desc",
 21→      },
 22→    });
 23→
 24→    return NextResponse.json(transactions);
 25→  } catch (error) {
 26→    if (error instanceof Error && error.message === "Unauthorized") {
 27→      return unauthorizedResponse();
 28→    }
 29→    console.error("Error fetching deleted transactions:", error);
 30→    return NextResponse.json(
 31→      { error: "Erro ao buscar transacoes excluidas" },
 32→      { status: 500 }
 33→    );
 34→  }
 35→}
 36→
 37→// PUT - Restore a transaction
 38→export async function PUT(request: NextRequest) {
 39→  try {
 40→    const userId = await getAuthenticatedUserId();
 41→
 42→    const body = await request.json();
 43→    const { id } = body;
 44→
 45→    if (!id) {
 46→      return NextResponse.json(
 47→        { error: "ID da transacao e obrigatorio" },
 48→        { status: 400 }
 49→      );
 50→    }
 51→
 52→    const transaction = await prisma.transaction.update({
 53→      where: { id, userId },
 54→      data: { deletedAt: null },
 55→      include: {
 56→        category: true,
 57→        installment: true,
 58→      },
 59→    });
 60→
 61→    return NextResponse.json(transaction);
 62→  } catch (error) {
 63→    if (error instanceof Error && error.message === "Unauthorized") {
 64→      return unauthorizedResponse();
 65→    }
 66→    console.error("Error restoring transaction:", error);
 67→    return NextResponse.json(
 68→      { error: "Erro ao restaurar transacao" },
 69→      { status: 500 }
 70→    );
 71→  }
 72→}
 73→
 74→// DELETE - Permanently delete items older than 30 days or specific item
 75→export async function DELETE(request: NextRequest) {
 76→  try {
 77→    const userId = await getAuthenticatedUserId();
 78→
 79→    const searchParams = request.nextUrl.searchParams;
 80→    const id = searchParams.get("id");
 81→    const cleanOld = searchParams.get("cleanOld");
 82→
 83→    if (id) {
 84→      // Delete specific transaction permanently
 85→      await prisma.transaction.delete({
 86→        where: { id, userId },
 87→      });
 88→      return NextResponse.json({ success: true, message: "Transacao excluida permanentemente" });
 89→    }
 90→
 91→    if (cleanOld === "true") {
 92→      // Delete all transactions deleted more than 30 days ago
 93→      const thirtyDaysAgo = new Date();
 94→      thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
 95→
 96→      const result = await prisma.transaction.deleteMany({
 97→        where: {
 98→          userId,
 99→          deletedAt: {
100→            not: null,
101→            lt: thirtyDaysAgo,
102→          },
103→        },
104→      });
105→
106→      return NextResponse.json({
107→        success: true,
108→        message: `${result.count} transacoes antigas excluidas permanentemente`,
109→        count: result.count,
110→      });
111→    }
112→
113→    return NextResponse.json(
114→      { error: "Parametro id ou cleanOld=true e obrigatorio" },
115→      { status: 400 }
116→    );
117→  } catch (error) {
118→    if (error instanceof Error && error.message === "Unauthorized") {
119→      return unauthorizedResponse();
120→    }
121→    console.error("Error permanently deleting transactions:", error);
122→    return NextResponse.json(
123→      { error: "Erro ao excluir transacoes permanentemente" },
124→      { status: 500 }
125→    );
126→  }
127→}
