 16→  Select,
 17→  SelectContent,
 18→  SelectItem,
 19→  SelectTrigger,
 20→  SelectValue,
 21→} from "@/components/ui/select";
 22→import { useToast } from "@/components/ui/use-toast";
 23→import { formatCurrency } from "@/lib/utils";
 24→import type { Category } from "@/types";
 25→
 26→interface RegisterPurchaseDialogProps {
 27→  open: boolean;
 28→  onOpenChange: (open: boolean) => void;
 29→  description: string;
 30→  totalAmount: number;
 31→  totalInstallments: number;
 32→  categoryId: string;
 33→  categories: Category[];
 34→  onSuccess: () => void;
 35→}
 36→
 37→export function RegisterPurchaseDialog({
 38→  open,
 39→  onOpenChange,
 40→  description,
 41→  totalAmount,
 42→  totalInstallments,
 43→  categoryId: initialCategoryId,
 44→  categories,
 45→  onSuccess,
 46→}: RegisterPurchaseDialogProps) {
 47→  const router = useRouter();
 48→  const { toast } = useToast();
 49→  const [loading, setLoading] = useState(false);
 50→  const [date, setDate] = useState(() => new Date().toISOString().split("T")[0]);
 51→  const [origin, setOrigin] = useState("");
 52→  const [selectedCategoryId, setSelectedCategoryId] = useState(initialCategoryId);
 53→
 54→  const installmentAmount = totalAmount / totalInstallments;
 55→
 56→  async function handleRegister() {
 57→    setLoading(true);
 58→    try {
 59→      const isInstallment = totalInstallments > 1;
 60→
 61→      const body: Record<string, unknown> = {
 62→        description,
 63→        amount: installmentAmount,
 64→        date,
 65→        type: "EXPENSE",
 66→        origin: origin || "Simulador",
 67→        categoryId: selectedCategoryId || null,
 68→        isFixed: false,
 69→        isInstallment,
 70→      };
 71→
 72→      if (isInstallment) {
 73→        body.totalInstallments = totalInstallments;
 74→        body.installmentAmount = installmentAmount;
 75→      }
 76→
 77→      const res = await fetch("/api/transactions", {
 78→        method: "POST",
 79→        headers: { "Content-Type": "application/json" },
 80→        body: JSON.stringify(body),
 81→      });
 82→
 83→      if (!res.ok) {
 84→        const error = await res.json();
 85→        throw new Error(error.error || "Erro ao registrar compra");
 86→      }
 87→
 88→      toast({ title: "Compra registrada com sucesso!" });
 89→      onSuccess();
 90→      router.push("/dashboard");
 91→    } catch (error) {
 92→      toast({
 93→        title: "Erro ao registrar compra",
 94→        description: error instanceof Error ? error.message : "Tente novamente",
 95→        variant: "destructive",
 96→      });
 97→    } finally {
 98→      setLoading(false);
 99→    }
100→  }
101→
102→  return (
103→    <Dialog open={open} onOpenChange={onOpenChange}>
104→      <DialogContent className="sm:max-w-[425px]">
105→        <DialogHeader>
106→          <DialogTitle>Registrar compra</DialogTitle>
107→        </DialogHeader>
108→
109→        <div className="space-y-4 py-4">
110→          {/* Summary */}
111→          <div className="rounded-lg bg-gray-50 p-4">
112→            <p className="font-medium text-gray-900">{description}</p>
113→            <p className="text-sm text-gray-500 mt-1">
114→              {totalInstallments > 1
115→                ? `${totalInstallments}x ${formatCurrency(installmentAmount)} (total: ${formatCurrency(totalAmount)})`
116→                : formatCurrency(totalAmount)}
117→            </p>
118→          </div>
119→
120→          <div className="space-y-2">
121→            <Label htmlFor="reg-date">Data da primeira parcela</Label>
122→            <Input
123→              id="reg-date"
124→              type="date"
125→              value={date}
126→              onChange={(e) => setDate(e.target.value)}
127→            />
128→          </div>
129→
130→          <div className="space-y-2">
131→            <Label htmlFor="reg-origin">Origem / Banco</Label>
132→            <Input
133→              id="reg-origin"
134→              placeholder="Ex: Cartão Nubank"
135→              value={origin}
136→              onChange={(e) => setOrigin(e.target.value)}
137→            />
138→          </div>
139→
140→          <div className="space-y-2">
141→            <Label htmlFor="reg-category">Categoria</Label>
142→            <Select value={selectedCategoryId} onValueChange={setSelectedCategoryId}>
143→              <SelectTrigger id="reg-category">
144→                <SelectValue placeholder="Selecione" />
145→              </SelectTrigger>
146→              <SelectContent>
147→                {categories.map((c) => (
148→                  <SelectItem key={c.id} value={c.id}>
149→                    <div className="flex items-center gap-2">
150→                      <div className="h-3 w-3 rounded-full" style={{ backgroundColor: c.color }} />
151→                      {c.name}
152→                    </div>
153→                  </SelectItem>
154→                ))}
155→              </SelectContent>
156→            </Select>
157→          </div>
158→        </div>
159→
160→        <DialogFooter>
161→          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={loading}>
162→            Cancelar
163→          </Button>
164→          <Button onClick={handleRegister} disabled={loading} className="bg-emerald-600 hover:bg-emerald-700">
165→            {loading ? "Registrando..." : "Confirmar compra"}
166→          </Button>
167→        </DialogFooter>
168→      </DialogContent>
169→    </Dialog>
170→  );
171→}
