      await addIssueToProject(issue.node_id);
    } catch (projectError) {
      console.error("Failed to add issue to project board:", projectError);
    }

    return NextResponse.json({
      success: true,
      issueNumber: issue.number,
      issueUrl: issue.html_url,
    });
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    console.error("Bug report error:", error);
    return NextResponse.json(
      { error: "Erro ao enviar o bug report. Tente novamente." },
      { status: 500 }
    );
  }
}
```

**Verification**: `npx vitest run src/app/api/bug-reports`

**On Failure**:
- Se erro de import: verificar que `@/lib/auth-utils` exporta as funções corretas
- Se erro de tipo no FormData: verificar cast `as File`
- Se teste falha por mock: verificar que global fetch está sendo mockado corretamente

---

#### 3. Criar integration test para a API route

**File**: `tests/integration/bug-reports.test.ts` (CREATE)
**Complexity**: Medium
**TDD**: YES (este É o teste)
**Depends On**: 2

**Load Before Implementing**:
1. `src/app/api/bug-reports/route.ts` (full file) — Rota sendo testada
2. `tests/integration/` (listar arquivos) — Padrão de testes de integração existentes

**Pre-conditions**:
- [ ] Diretório `tests/integration/` existe
- [ ] Task 2 (API route) está implementada

**Why**: Garante que a API route funciona corretamente com mocks do GitHub API, cobrindo happy path e error cases.

**Acceptance Criteria**:
```gherkin
Given a valid POST with title and description
When the API is called with mocked GitHub responses
Then it returns 200 with success: true, issueNumber, and issueUrl

Given a POST without authentication
When the API is called
Then it returns 401

Given a POST with missing title
When the API is called
Then it returns 400 with error message

Given a POST with an image over 5MB
When the API is called
Then it returns 400 with size error message
```

**Implementation**:
```typescript
import { describe, it, expect, vi, beforeEach } from "vitest";
import { POST } from "@/app/api/bug-reports/route";
import { NextRequest } from "next/server";

// Mock auth
vi.mock("@/lib/auth-utils", () => ({
  getAuthenticatedUserId: vi.fn(),
  unauthorizedResponse: vi.fn(() =>
    new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 })
  ),
}));

// Mock environment
vi.stubEnv("GITHUB_TOKEN", "test-token");

const mockFetch = vi.fn();
global.fetch = mockFetch;

const { getAuthenticatedUserId } = await import("@/lib/auth-utils");

function createFormData(fields: Record<string, string>, files?: { name: string; content: Buffer; type: string }[]) {
  const formData = new FormData();
  for (const [key, value] of Object.entries(fields)) {
    formData.append(key, value);
  }
  if (files) {
    for (const file of files) {
      const blob = new Blob([file.content], { type: file.type });
      formData.append("images", blob, file.name);
    }
  }
  return formData;
}

function createRequest(formData: FormData) {
  return new NextRequest("http://localhost:3000/api/bug-reports", {
    method: "POST",
    body: formData,
  });
}

describe("/api/bug-reports", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    (getAuthenticatedUserId as ReturnType<typeof vi.fn>).mockResolvedValue("user-1");
  });

  it("creates a GitHub issue successfully", async () => {
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve({
        number: 42,
        html_url: "https://github.com/vverzellesi/expense-control/issues/42",
        node_id: "I_abc123",
      }),
    });

    // Mock project query
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve({
        data: { user: { projectV2: { id: "PVT_123" } } },
      }),
    });

    // Mock add to project
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve({
        data: { addProjectV2ItemById: { item: { id: "PVTI_123" } } },
      }),
    });

    const formData = createFormData({
      title: "Bug no dashboard",
      description: "O gráfico não carrega",
      userAgent: "Mozilla/5.0",
      pageUrl: "/dashboard",
    });

    const response = await POST(createRequest(formData));
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.success).toBe(true);
    expect(data.issueNumber).toBe(42);
    expect(data.issueUrl).toContain("issues/42");

    // Verify issue creation call
    const issueCall = mockFetch.mock.calls[0];
    expect(issueCall[0]).toContain("/issues");
    const issueBody = JSON.parse(issueCall[1].body);
    expect(issueBody.title).toBe("Bug no dashboard");
    expect(issueBody.labels).toEqual(["bug"]);
    expect(issueBody.body).toContain("O gráfico não carrega");
    expect(issueBody.body).toContain("/dashboard");
    expect(issueBody.body).toContain("Mozilla/5.0");
  });

  it("returns 401 when not authenticated", async () => {
    (getAuthenticatedUserId as ReturnType<typeof vi.fn>).mockRejectedValue(
      new Error("Unauthorized")
    );

    const formData = createFormData({
      title: "Bug",
      description: "Descrição",
    });

    const response = await POST(createRequest(formData));
    expect(response.status).toBe(401);
  });

  it("returns 400 when title is missing", async () => {
    const formData = createFormData({
      title: "",
      description: "Descrição",
    });

    const response = await POST(createRequest(formData));
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data.error).toContain("obrigatórios");
  });

  it("returns 400 when description is missing", async () => {
    const formData = createFormData({
      title: "Bug",
      description: "",
    });

    const response = await POST(createRequest(formData));
    expect(response.status).toBe(400);
  });

  it("returns 400 when image exceeds 5MB", async () => {
    const largeBuffer = Buffer.alloc(6 * 1024 * 1024); // 6MB

    const formData = createFormData(
      { title: "Bug", description: "Descrição" },
      [{ name: "large.png", content: largeBuffer, type: "image/png" }]
    );

    const response = await POST(createRequest(formData));
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data.error).toContain("5MB");
  });

  it("returns 400 for unsupported image type", async () => {
    const formData = createFormData(
      { title: "Bug", description: "Descrição" },
      [{ name: "doc.pdf", content: Buffer.from("fake"), type: "application/pdf" }]
    );

    const response = await POST(createRequest(formData));
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data.error).toContain("não suportado");
  });

  it("uploads images and embeds URLs in issue body", async () => {
    // Mock image upload
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve({
        content: { download_url: "https://raw.githubusercontent.com/test/image.png" },
      }),
    });

    // Mock issue creation
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve({
        number: 43,
        html_url: "https://github.com/vverzellesi/expense-control/issues/43",
        node_id: "I_def456",
      }),
    });

    // Mock project query
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve({
        data: { user: { projectV2: { id: "PVT_123" } } },
      }),
    });

    // Mock add to project
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve({
        data: { addProjectV2ItemById: { item: { id: "PVTI_456" } } },
      }),
    });

    const formData = createFormData(
      { title: "Bug com imagem", description: "Veja o screenshot" },
      [{ name: "screenshot.png", content: Buffer.from("fake-image"), type: "image/png" }]
    );

    const response = await POST(createRequest(formData));
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.success).toBe(true);

    // Verify image upload was called
    const uploadCall = mockFetch.mock.calls[0];
    expect(uploadCall[0]).toContain("bug-attachments");

    // Verify issue body contains image markdown
    const issueCall = mockFetch.mock.calls[1];
    const issueBody = JSON.parse(issueCall[1].body);
    expect(issueBody.body).toContain("![anexo-1]");
    expect(issueBody.body).toContain("raw.githubusercontent.com");
  });
});
```

**Verification**: `npx vitest run tests/integration/bug-reports.test.ts`

**On Failure**:
- Se erro de import: verificar path `@/app/api/bug-reports/route`
- Se FormData não funciona no test: verificar ambiente Node.js 18+ (FormData nativo)
- Se mock de fetch interfere com outros testes: verificar `beforeEach` limpa mocks

---

## Success Criteria

