299→    // Process images
300→    const imageUrls: string[] = [];
301→    const imageEntries = formData.getAll("images");
302→
303→    if (imageEntries.length > MAX_IMAGES) {
304→      return NextResponse.json(
305→        { error: `Máximo de ${MAX_IMAGES} imagens permitidas.` },
306→        { status: 400 }
307→      );
308→    }
309→
310→    for (const entry of imageEntries) {
311→      if (!(entry instanceof File) || entry.size === 0) continue;
312→
313→      if (!ALLOWED_IMAGE_TYPES.includes(entry.type)) {
314→        return NextResponse.json(
315→          { error: `Tipo de arquivo não suportado: ${entry.type}. Use PNG, JPG ou GIF.` },
316→          { status: 400 }
317→        );
318→      }
319→
320→      if (entry.size > MAX_IMAGE_SIZE) {
321→        return NextResponse.json(
322→          { error: `Imagem "${entry.name}" excede o limite de 5MB.` },
323→          { status: 400 }
324→        );
325→      }
326→
327→      const buffer = Buffer.from(await entry.arrayBuffer());
328→      const base64 = buffer.toString("base64");
329→      const ext = entry.name.split(".").pop() || "png";
330→      const sanitizedName = `${imageUrls.length}.${ext}`;
331→
332→      const downloadUrl = await uploadImageToGitHub(base64, sanitizedName);
333→      imageUrls.push(downloadUrl);
334→    }
335→
336→    // Create issue
337→    const body = buildIssueBody(description.trim(), userAgent, pageUrl, imageUrls);
338→    const issue = await createGitHubIssue(title.trim(), body);
339→
340→    // Add to project board (non-blocking — don't fail the request if this fails)
341→    try {
342→      await addIssueToProject(issue.node_id);
343→    } catch (projectError) {
344→      console.error("Failed to add issue to project board:", projectError);
345→    }
346→
347→    return NextResponse.json({
348→      success: true,
349→      issueNumber: issue.number,
350→      issueUrl: issue.html_url,
351→    });
352→  } catch (error) {
353→    if (error instanceof Error && error.message === "Unauthorized") {
354→      return unauthorizedResponse();
355→    }
356→    console.error("Bug report error:", error);
357→    return NextResponse.json(
358→      { error: "Erro ao enviar o bug report. Tente novamente." },
359→      { status: 500 }
360→    );
361→  }
362→}
363→```
