  for (const [key, value] of Object.entries(fields)) {
    formData.append(key, value);
  }
  if (files) {
    for (const file of files) {
      const blob = new Blob([file.content], { type: file.type });
      formData.append("images", blob, file.name);
    }
  }
  return formData;
}

