  3→
  4→const GITHUB_OWNER = "vverzellesi";
  5→const GITHUB_REPO = "expense-control";
  6→const GITHUB_PROJECT_NUMBER = 2;
  7→const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB
  8→const MAX_IMAGES = 3;
  9→const ALLOWED_IMAGE_TYPES = ["image/png", "image/jpeg", "image/gif"];
 10→
 11→function getGitHubToken(): string | undefined {
 12→  return process.env.GITHUB_TOKEN;
 13→}
 14→
 15→function isFileLike(entry: FormDataEntryValue): entry is File {
 16→  return typeof entry === "object" && "arrayBuffer" in entry && "size" in entry && "type" in entry;
 17→}
