 19→async function uploadImageToGitHub(
 20→  token: string,
 21→  base64Content: string,
 22→  filename: string
 23→): Promise<string> {
 24→  const path = `bug-attachments/${Date.now()}-${filename}`;
 25→
 26→  const response = await fetch(
 27→    `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/contents/${path}`,
 28→    {
 29→      method: "PUT",
 30→      headers: {
 31→        Authorization: `Bearer ${token}`,
 32→        "Content-Type": "application/json",
 33→        Accept: "application/vnd.github.v3+json",
 34→      },
 35→      body: JSON.stringify({
 36→        message: `bug-report: add attachment ${filename}`,
 37→        content: base64Content,
 38→      }),
 39→    }
 40→  );
 41→
 42→  if (!response.ok) {
 43→    const error = await response.json().catch(() => ({}));
 44→    throw new Error(
 45→      `Failed to upload image: ${error.message || response.statusText}`
 46→    );
 47→  }
 48→
 49→  const data = await response.json();
 50→  return data.content.download_url;
 51→}
