 53→async function createGitHubIssue(
 54→  token: string,
 55→  title: string,
 56→  body: string
 57→): Promise<{ number: number; html_url: string; node_id: string }> {
 58→  // Try with label first, fallback without if label doesn't exist
 59→  const payload = { title, body, labels: ["bug"] };
 60→
 61→  let response = await fetch(
 62→    `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/issues`,
 63→    {
 64→      method: "POST",
 65→      headers: {
 66→        Authorization: `Bearer ${token}`,
 67→        "Content-Type": "application/json",
 68→        Accept: "application/vnd.github.v3+json",
 69→      },
 70→      body: JSON.stringify(payload),
 71→    }
 72→  );
 73→
 74→  // If 422 (likely label doesn't exist), retry without labels
 75→  if (response.status === 422) {
 76→    console.warn("Label 'bug' may not exist, retrying without labels");
 77→    response = await fetch(
 78→      `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/issues`,
 79→      {
 80→        method: "POST",
 81→        headers: {
 82→          Authorization: `Bearer ${token}`,
 83→          "Content-Type": "application/json",
 84→          Accept: "application/vnd.github.v3+json",
 85→        },
 86→        body: JSON.stringify({ title, body }),
 87→      }
 88→    );
 89→  }
 90→
 91→  if (!response.ok) {
 92→    const error = await response.json().catch(() => ({}));
 93→    throw new Error(
 94→      `Failed to create issue: ${error.message || response.statusText}`
 95→    );
 96→  }
 97→
 98→  return response.json();
 99→}
