215→async function addIssueToProject(token: string, issueNodeId: string): Promise<boolean> {
216→  // First, get the project node ID from the project number
217→  const projectQuery = `
218→    query {
219→      user(login: "${GITHUB_OWNER}") {
220→        projectV2(number: ${GITHUB_PROJECT_NUMBER}) {
221→          id
222→        }
223→      }
224→    }
225→  `;
226→
227→  const projectResponse = await fetch("https://api.github.com/graphql", {
228→    method: "POST",
229→    headers: {
230→      Authorization: `Bearer ${token}`,
231→      "Content-Type": "application/json",
232→    },
233→    body: JSON.stringify({ query: projectQuery }),
234→  });
235→
236→  if (!projectResponse.ok) {
237→    console.error("Failed to fetch project ID — check GITHUB_TOKEN has 'project' scope");
238→    return false;
239→  }
240→
241→  const projectData = await projectResponse.json();
242→  const projectId = projectData.data?.user?.projectV2?.id;
243→
244→  if (!projectId) {
245→    console.error("Project not found — verify project number and token permissions");
246→    return false;
247→  }
248→
249→  // Add the issue to the project
250→  const mutation = `
251→    mutation {
252→      addProjectV2ItemById(input: {
253→        projectId: "${projectId}"
254→        contentId: "${issueNodeId}"
255→      }) {
256→        item {
257→          id
258→        }
259→      }
260→    }
261→  `;
262→
263→  const response = await fetch("https://api.github.com/graphql", {
264→    method: "POST",
265→    headers: {
266→      Authorization: `Bearer ${token}`,
267→      "Content-Type": "application/json",
268→    },
269→    body: JSON.stringify({ query: mutation }),
270→  });
271→
272→  if (!response.ok) {
273→    console.error("Failed to add issue to project — check token 'project' scope");
274→    return false;
275→  }
276→
277→  return true;
278→}
