312→      );
313→    }
314→
315→    const formData = await request.formData();
316→    const title = formData.get("title") as string | null;
317→    const description = formData.get("description") as string | null;
318→    const userAgent = (formData.get("userAgent") as string) || "Unknown";
319→    const pageUrl = (formData.get("pageUrl") as string) || "Unknown";
320→
321→    if (!title?.trim() || !description?.trim()) {
322→      return NextResponse.json(
323→        { error: "Título e descrição são obrigatórios." },
324→        { status: 400 }
325→      );
326→    }
327→
328→    // Process images
329→    const imageUrls: string[] = [];
330→    const imageEntries = formData.getAll("images");
331→
332→    if (imageEntries.length > MAX_IMAGES) {
333→      return NextResponse.json(
334→        { error: `Máximo de ${MAX_IMAGES} imagens permitidas.` },
335→        { status: 400 }
336→      );
337→    }
338→
339→    for (const entry of imageEntries) {
340→      if (!isFileLike(entry) || entry.size === 0) continue;
341→
342→      if (!ALLOWED_IMAGE_TYPES.includes(entry.type)) {
343→        return NextResponse.json(
344→          { error: `Tipo de arquivo não suportado: ${entry.type}. Use PNG, JPG ou GIF.` },
345→          { status: 400 }
346→        );
347→      }
348→
349→      if (entry.size > MAX_IMAGE_SIZE) {
350→        return NextResponse.json(
351→          { error: `Imagem "${entry.name}" excede o limite de 5MB.` },
352→          { status: 400 }
353→        );
354→      }
355→
356→      const buffer = Buffer.from(await entry.arrayBuffer());
357→      const base64 = buffer.toString("base64");
358→      const ext = entry.name.split(".").pop() || "png";
359→      const sanitizedName = `${imageUrls.length}.${ext}`;
360→
361→      const downloadUrl = await uploadImageToGitHub(token, base64, sanitizedName);
362→      imageUrls.push(downloadUrl);
363→    }
364→
365→    // Create issue
366→    const body = buildIssueBody(description.trim(), userAgent, pageUrl, imageUrls);
367→    const issue = await createGitHubIssue(token, title.trim(), body);
368→
369→    // Add to project board (best-effort — don't fail the request if this fails)
370→    let projectLinked = false;
371→    try {
372→      projectLinked = await addIssueToProject(token, issue.node_id);
373→    } catch (projectError) {
374→      console.error("Failed to add issue to project board:", projectError);
375→    }
376→
377→    return NextResponse.json({
378→      success: true,
379→      issueNumber: issue.number,
380→      issueUrl: issue.html_url,
381→      projectLinked,
382→    });
383→  } catch (error) {
384→    if (error instanceof Error && error.message === "Unauthorized") {
385→      return unauthorizedResponse();
386→    }
387→    console.error("Bug report error:", error);
388→    return NextResponse.json(
389→      { error: "Erro ao enviar o bug report. Tente novamente." },
390→      { status: 500 }
391→    );
392→  }
393→}
