 68→
 69→#### 2. Criar API route `/api/bug-reports` com integração GitHub
 70→
 71→**File**: `src/app/api/bug-reports/route.ts` (CREATE)
 72→**Complexity**: High
 73→**TDD**: YES
 74→**Depends On**: none
 75→
 76→**Load Before Implementing**:
 77→1. `src/lib/auth-utils.ts` (full file) — Funções de autenticação
 78→2. `src/app/api/ocr/route.ts` (lines 1-30) — Padrão de FormData handling
 79→3. `REDACTED.md` (section: GitHub API) — Endpoints e autenticação
 80→
 81→**Pre-conditions**:
 82→- [ ] Diretório `src/app/api/bug-reports/` não existe
 83→- [ ] `src/lib/auth-utils.ts` exporta `getAuthenticatedUserId` e `unauthorizedResponse`
 84→
 85→**Why**: Endpoint central que recebe o bug report, faz upload de imagens para o GitHub, cria a Issue e vincula ao Project Board. Atua como proxy protegendo o token.
 86→
 87→**Acceptance Criteria**:
 88→```gherkin
 89→Given a POST request with valid title, description, userAgent, and pageUrl
 90→When the API processes the request
 91→Then a GitHub Issue is created with title, formatted body (description + metadados), and label "bug"
 92→And the response contains { success: true, issueNumber, issueUrl, projectLinked: boolean }
 93→And projectLinked indicates whether the Issue was linked to Project Board #2 (best-effort)
 94→
 95→Given a POST request with images attached
 96→When the API processes the request
 97→Then each image is uploaded to GitHub Contents API at bug-attachments/{timestamp}-{index}.{ext}
 98→And image URLs are embedded in the Issue body as markdown images
 99→
100→Given a POST request without authentication
101→When the API processes the request
102→Then a 401 response is returned
103→
104→Given a POST request with missing title or description
105→When the API processes the request
106→Then a 400 response is returned with error message
107→
108→Given a POST request with an image exceeding 5MB
109→When the API processes the request
110→Then a 400 response is returned with error message about file size
111→```
112→
113→**Implementation**:
114→```typescript
115→import { NextRequest, NextResponse } from "next/server";
116→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
117→
118→const GITHUB_OWNER = "vverzellesi";
119→const GITHUB_REPO = "expense-control";
120→const GITHUB_PROJECT_NUMBER = 2;
121→const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB
122→const MAX_IMAGES = 3;
123→const ALLOWED_IMAGE_TYPES = ["image/png", "image/jpeg", "image/gif"];
124→
125→function getGitHubToken(): string | undefined {
126→  return process.env.GITHUB_TOKEN;
127→}
128→
129→function isFileLike(entry: FormDataEntryValue): entry is File {
130→  return typeof entry === "object" && "arrayBuffer" in entry && "size" in entry && "type" in entry;
131→}
132→
133→async function uploadImageToGitHub(
134→  token: string,
135→  base64Content: string,
136→  filename: string
137→): Promise<string> {
138→  const path = `bug-attachments/${Date.now()}-${filename}`;
139→
140→  const response = await fetch(
141→    `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/contents/${path}`,
142→    {
143→      method: "PUT",
144→      headers: {
145→        Authorization: `Bearer ${token}`,
146→        "Content-Type": "application/json",
147→        Accept: "application/vnd.github.v3+json",
148→      },
149→      body: JSON.stringify({
150→        message: `bug-report: add attachment ${filename}`,
151→        content: base64Content,
152→      }),
153→    }
154→  );
155→
156→  if (!response.ok) {
157→    const error = await response.json().catch(() => ({}));
158→    throw new Error(
159→      `Failed to upload image: ${error.message || response.statusText}`
160→    );
161→  }
162→
163→  const data = await response.json();
164→  return data.content.download_url;
165→}
166→
167→async function createGitHubIssue(
168→  token: string,
169→  title: string,
170→  body: string
171→): Promise<{ number: number; html_url: string; node_id: string }> {
172→  // Try with label first, fallback without if label doesn't exist
173→  const payload = { title, body, labels: ["bug"] };
174→
175→  let response = await fetch(
176→    `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/issues`,
177→    {
178→      method: "POST",
179→      headers: {
180→        Authorization: `Bearer ${token}`,
181→        "Content-Type": "application/json",
182→        Accept: "application/vnd.github.v3+json",
183→      },
184→      body: JSON.stringify(payload),
185→    }
186→  );
187→
188→  // If 422 (likely label doesn't exist), retry without labels
189→  if (response.status === 422) {
190→    console.warn("Label 'bug' may not exist, retrying without labels");
191→    response = await fetch(
192→      `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/issues`,
193→      {
194→        method: "POST",
195→        headers: {
196→          Authorization: `Bearer ${token}`,
197→          "Content-Type": "application/json",
198→          Accept: "application/vnd.github.v3+json",
199→        },
200→        body: JSON.stringify({ title, body }),
201→      }
202→    );
203→  }
204→
205→  if (!response.ok) {
206→    const error = await response.json().catch(() => ({}));
207→    throw new Error(
208→      `Failed to create issue: ${error.message || response.statusText}`
209→    );
210→  }
211→
212→  return response.json();
213→}
214→
215→async function addIssueToProject(token: string, issueNodeId: string): Promise<boolean> {
216→  // First, get the project node ID from the project number
217→  const projectQuery = `
218→    query {
219→      user(login: "${GITHUB_OWNER}") {
220→        projectV2(number: ${GITHUB_PROJECT_NUMBER}) {
221→          id
222→        }
223→      }
224→    }
225→  `;
226→
227→  const projectResponse = await fetch("https://api.github.com/graphql", {
228→    method: "POST",
229→    headers: {
230→      Authorization: `Bearer ${token}`,
231→      "Content-Type": "application/json",
232→    },
233→    body: JSON.stringify({ query: projectQuery }),
234→  });
235→
236→  if (!projectResponse.ok) {
237→    console.error("Failed to fetch project ID — check GITHUB_TOKEN has 'project' scope");
238→    return false;
239→  }
240→
241→  const projectData = await projectResponse.json();
242→  const projectId = projectData.data?.user?.projectV2?.id;
243→
244→  if (!projectId) {
245→    console.error("Project not found — verify project number and token permissions");
246→    return false;
247→  }
248→
249→  // Add the issue to the project
250→  const mutation = `
251→    mutation {
252→      addProjectV2ItemById(input: {
253→        projectId: "${projectId}"
254→        contentId: "${issueNodeId}"
255→      }) {
256→        item {
257→          id
258→        }
259→      }
260→    }
261→  `;
262→
263→  const response = await fetch("https://api.github.com/graphql", {
264→    method: "POST",
265→    headers: {
266→      Authorization: `Bearer ${token}`,
267→      "Content-Type": "application/json",
268→    },
269→    body: JSON.stringify({ query: mutation }),
270→  });
271→
272→  if (!response.ok) {
273→    console.error("Failed to add issue to project — check token 'project' scope");
274→    return false;
275→  }
276→
277→  return true;
278→}
279→
280→function buildIssueBody(
281→  description: string,
282→  userAgent: string,
283→  pageUrl: string,
284→  imageUrls: string[]
285→): string {
286→  let body = description;
287→
288→  if (imageUrls.length > 0) {
289→    body += "\n\n### Anexos\n\n";
290→    imageUrls.forEach((url, index) => {
291→      body += `![anexo-${index + 1}](${url})\n\n`;
292→    });
293→  }
294→
295→  body += "\n\n---\n\n";
296→  body += `**Página:** ${pageUrl}\n`;
297→  body += `**User Agent:** ${userAgent}\n`;
298→  body += `**Reportado via:** MyPocket Bug Report\n`;
299→
300→  return body;
301→}
302→
303→export async function POST(request: NextRequest) {
304→  try {
305→    const userId = await getAuthenticatedUserId();
306→
307→    const token = getGitHubToken();
308→    if (!token) {
309→      return NextResponse.json(
310→        { error: "Configuração do GitHub não encontrada." },
311→        { status: 500 }
312→      );
313→    }
314→
315→    const formData = await request.formData();
316→    const title = formData.get("title") as string | null;
317→    const description = formData.get("description") as string | null;
318→    const userAgent = (formData.get("userAgent") as string) || "Unknown";
319→    const pageUrl = (formData.get("pageUrl") as string) || "Unknown";
320→
321→    if (!title?.trim() || !description?.trim()) {
322→      return NextResponse.json(
323→        { error: "Título e descrição são obrigatórios." },
324→        { status: 400 }
325→      );
326→    }
327→
328→    // Process images
329→    const imageUrls: string[] = [];
330→    const imageEntries = formData.getAll("images");
331→
332→    if (imageEntries.length > MAX_IMAGES) {
333→      return NextResponse.json(
334→        { error: `Máximo de ${MAX_IMAGES} imagens permitidas.` },
335→        { status: 400 }
336→      );
337→    }
338→
339→    for (const entry of imageEntries) {
340→      if (!isFileLike(entry) || entry.size === 0) continue;
341→
342→      if (!ALLOWED_IMAGE_TYPES.includes(entry.type)) {
343→        return NextResponse.json(
344→          { error: `Tipo de arquivo não suportado: ${entry.type}. Use PNG, JPG ou GIF.` },
345→          { status: 400 }
346→        );
347→      }
348→
349→      if (entry.size > MAX_IMAGE_SIZE) {
350→        return NextResponse.json(
351→          { error: `Imagem "${entry.name}" excede o limite de 5MB.` },
352→          { status: 400 }
353→        );
354→      }
355→
356→      const buffer = Buffer.from(await entry.arrayBuffer());
357→      const base64 = buffer.toString("base64");
358→      const ext = entry.name.split(".").pop() || "png";
359→      const sanitizedName = `${imageUrls.length}.${ext}`;
360→
361→      const downloadUrl = await uploadImageToGitHub(token, base64, sanitizedName);
362→      imageUrls.push(downloadUrl);
363→    }
364→
365→    // Create issue
366→    const body = buildIssueBody(description.trim(), userAgent, pageUrl, imageUrls);
367→    const issue = await createGitHubIssue(token, title.trim(), body);
368→
369→    // Add to project board (best-effort — don't fail the request if this fails)
370→    let projectLinked = false;
371→    try {
372→      projectLinked = await addIssueToProject(token, issue.node_id);
373→    } catch (projectError) {
374→      console.error("Failed to add issue to project board:", projectError);
375→    }
376→
377→    return NextResponse.json({
378→      success: true,
379→      issueNumber: issue.number,
380→      issueUrl: issue.html_url,
381→      projectLinked,
382→    });
383→  } catch (error) {
384→    if (error instanceof Error && error.message === "Unauthorized") {
385→      return unauthorizedResponse();
386→    }
387→    console.error("Bug report error:", error);
388→    return NextResponse.json(
389→      { error: "Erro ao enviar o bug report. Tente novamente." },
390→      { status: 500 }
391→    );
392→  }
393→}
394→```
395→
396→**Verification**: `npx vitest run src/app/api/bug-reports`
397→
398→**On Failure**:
399→- Se erro de import: verificar que `@/lib/auth-utils` exporta as funções corretas
400→- Se erro de tipo no FormData: verificar cast `as File`
401→- Se teste falha por mock: verificar que global fetch está sendo mockado corretamente
402→
403→---
404→
405→#### 3. Criar integration test para a API route
