112→      setLoading(false);
113→      setIsDragOver(false);
114→    }
115→  }, [isOpen]);
116→
117→  // Cleanup preview URLs on unmount
118→  useEffect(() => {
119→    return () => {
120→      images.forEach((img) => URL.revokeObjectURL(img.previewUrl));
121→    };
122→  }, [images]);
123→
124→  function validateAndAddFiles(files: FileList | File[]) {
125→    const fileArray = Array.from(files);
126→
127→    for (const file of fileArray) {
128→      if (images.length >= MAX_IMAGES) {
129→        toast({
130→          title: "Limite de imagens",
