101→async function addIssueToProject(token: string, issueNodeId: string): Promise<boolean> {
102→  // First, get the project node ID from the project number
103→  const projectQuery = `
104→    query {
105→      user(login: "${GITHUB_OWNER}") {
106→        projectV2(number: ${GITHUB_PROJECT_NUMBER}) {
107→          id
108→        }
109→      }
110→    }
111→  `;
112→
113→  const projectResponse = await fetch("https://api.github.com/graphql", {
114→    method: "POST",
115→    headers: {
116→      Authorization: `Bearer ${token}`,
117→      "Content-Type": "application/json",
118→    },
119→    body: JSON.stringify({ query: projectQuery }),
120→  });
121→
122→  if (!projectResponse.ok) {
123→    console.error("Failed to fetch project ID — check GITHUB_TOKEN has 'project' scope");
124→    return false;
125→  }
126→
127→  const projectData = await projectResponse.json();
128→  const projectId = projectData.data?.user?.projectV2?.id;
129→
130→  if (!projectId) {
131→    console.error("Project not found — verify project number and token permissions");
132→    return false;
133→  }
134→
135→  // Add the issue to the project
136→  const mutation = `
137→    mutation {
138→      addProjectV2ItemById(input: {
139→        projectId: "${projectId}"
140→        contentId: "${issueNodeId}"
141→      }) {
142→        item {
143→          id
144→        }
145→      }
146→    }
147→  `;
148→
149→  const response = await fetch("https://api.github.com/graphql", {
150→    method: "POST",
151→    headers: {
152→      Authorization: `Bearer ${token}`,
153→      "Content-Type": "application/json",
154→    },
155→    body: JSON.stringify({ query: mutation }),
156→  });
157→
158→  if (!response.ok) {
159→    console.error("Failed to add issue to project — check token 'project' scope");
160→    return false;
161→  }
162→
163→  return true;
164→}
