 67→
 68→---
 69→
 70→#### 2. Criar API route `/api/bug-reports` com integração GitHub - [x] DONE
 71→
 72→**File**: `src/app/api/bug-reports/route.ts` (CREATE)
 73→**Complexity**: High
 74→**TDD**: YES
 75→**Depends On**: none
 76→- **Learning:** Variável `userId` é obtida mas não usada no corpo da função (apenas para autenticação). O padrão é consistente com outras rotas do projeto.
 77→
 78→**Load Before Implementing**:
 79→1. `src/lib/auth-utils.ts` (full file) — Funções de autenticação
 80→2. `src/app/api/ocr/route.ts` (lines 1-30) — Padrão de FormData handling
 81→3. `REDACTED.md` (section: GitHub API) — Endpoints e autenticação
 82→
 83→**Pre-conditions**:
 84→- [ ] Diretório `src/app/api/bug-reports/` não existe
 85→- [ ] `src/lib/auth-utils.ts` exporta `getAuthenticatedUserId` e `unauthorizedResponse`
 86→
 87→**Why**: Endpoint central que recebe o bug report, faz upload de imagens para o GitHub, cria a Issue e vincula ao Project Board. Atua como proxy protegendo o token.
 88→
 89→**Acceptance Criteria**:
 90→```gherkin
 91→Given a POST request with valid title, description, userAgent, and pageUrl
 92→When the API processes the request
 93→Then a GitHub Issue is created with title, formatted body (description + metadados), and label "bug"
 94→And the response contains { success: true, issueNumber, issueUrl, projectLinked: boolean }
 95→And projectLinked indicates whether the Issue was linked to Project Board #2 (best-effort)
 96→
 97→Given a POST request with images attached
 98→When the API processes the request
 99→Then each image is uploaded to GitHub Contents API at bug-attachments/{timestamp}-{index}.{ext}
100→And image URLs are embedded in the Issue body as markdown images
101→
102→Given a POST request without authentication
103→When the API processes the request
104→Then a 401 response is returned
105→
106→Given a POST request with missing title or description
107→When the API processes the request
108→Then a 400 response is returned with error message
109→
110→Given a POST request with an image exceeding 5MB
111→When the API processes the request
112→Then a 400 response is returned with error message about file size
113→```
114→
115→**Implementation**:
116→```typescript
117→import { NextRequest, NextResponse } from "next/server";
118→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
119→
120→const GITHUB_OWNER = "vverzellesi";
121→const GITHUB_REPO = "expense-control";
122→const GITHUB_PROJECT_NUMBER = 2;
123→const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB
124→const MAX_IMAGES = 3;
125→const ALLOWED_IMAGE_TYPES = ["image/png", "image/jpeg", "image/gif"];
126→
127→function getGitHubToken(): string | undefined {
128→  return process.env.GITHUB_TOKEN;
129→}
130→
131→function isFileLike(entry: FormDataEntryValue): entry is File {
132→  return typeof entry === "object" && "arrayBuffer" in entry && "size" in entry && "type" in entry;
133→}
134→
135→async function uploadImageToGitHub(
136→  token: string,
137→  base64Content: string,
138→  filename: string
139→): Promise<string> {
140→  const path = `bug-attachments/${Date.now()}-${filename}`;
141→
142→  const response = await fetch(
143→    `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/contents/${path}`,
144→    {
145→      method: "PUT",
146→      headers: {
147→        Authorization: `Bearer ${token}`,
148→        "Content-Type": "application/json",
149→        Accept: "application/vnd.github.v3+json",
150→      },
151→      body: JSON.stringify({
152→        message: `bug-report: add attachment ${filename}`,
153→        content: base64Content,
154→      }),
155→    }
156→  );
157→
158→  if (!response.ok) {
159→    const error = await response.json().catch(() => ({}));
160→    throw new Error(
161→      `Failed to upload image: ${error.message || response.statusText}`
162→    );
163→  }
164→
165→  const data = await response.json();
166→  return data.content.download_url;
167→}
168→
169→async function createGitHubIssue(
170→  token: string,
171→  title: string,
172→  body: string
173→): Promise<{ number: number; html_url: string; node_id: string }> {
174→  // Try with label first, fallback without if label doesn't exist
175→  const payload = { title, body, labels: ["bug"] };
176→
177→  let response = await fetch(
178→    `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/issues`,
179→    {
180→      method: "POST",
181→      headers: {
182→        Authorization: `Bearer ${token}`,
183→        "Content-Type": "application/json",
184→        Accept: "application/vnd.github.v3+json",
185→      },
186→      body: JSON.stringify(payload),
187→    }
188→  );
189→
190→  // If 422 (likely label doesn't exist), retry without labels
191→  if (response.status === 422) {
192→    console.warn("Label 'bug' may not exist, retrying without labels");
193→    response = await fetch(
194→      `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/issues`,
195→      {
196→        method: "POST",
197→        headers: {
198→          Authorization: `Bearer ${token}`,
199→          "Content-Type": "application/json",
200→          Accept: "application/vnd.github.v3+json",
201→        },
202→        body: JSON.stringify({ title, body }),
203→      }
204→    );
205→  }
206→
207→  if (!response.ok) {
208→    const error = await response.json().catch(() => ({}));
209→    throw new Error(
210→      `Failed to create issue: ${error.message || response.statusText}`
211→    );
212→  }
213→
214→  return response.json();
215→}
216→
217→async function addIssueToProject(token: string, issueNodeId: string): Promise<boolean> {
218→  // First, get the project node ID from the project number
219→  const projectQuery = `
220→    query {
221→      user(login: "${GITHUB_OWNER}") {
222→        projectV2(number: ${GITHUB_PROJECT_NUMBER}) {
223→          id
224→        }
225→      }
226→    }
227→  `;
228→
229→  const projectResponse = await fetch("https://api.github.com/graphql", {
230→    method: "POST",
231→    headers: {
232→      Authorization: `Bearer ${token}`,
233→      "Content-Type": "application/json",
234→    },
235→    body: JSON.stringify({ query: projectQuery }),
236→  });
237→
238→  if (!projectResponse.ok) {
239→    console.error("Failed to fetch project ID — check GITHUB_TOKEN has 'project' scope");
240→    return false;
241→  }
242→
243→  const projectData = await projectResponse.json();
244→  const projectId = projectData.data?.user?.projectV2?.id;
245→
246→  if (!projectId) {
247→    console.error("Project not found — verify project number and token permissions");
248→    return false;
249→  }
250→
251→  // Add the issue to the project
252→  const mutation = `
253→    mutation {
254→      addProjectV2ItemById(input: {
255→        projectId: "${projectId}"
256→        contentId: "${issueNodeId}"
257→      }) {
258→        item {
259→          id
260→        }
261→      }
262→    }
263→  `;
264→
265→  const response = await fetch("https://api.github.com/graphql", {
266→    method: "POST",
267→    headers: {
268→      Authorization: `Bearer ${token}`,
269→      "Content-Type": "application/json",
270→    },
271→    body: JSON.stringify({ query: mutation }),
272→  });
273→
274→  if (!response.ok) {
275→    console.error("Failed to add issue to project — check token 'project' scope");
276→    return false;
277→  }
278→
279→  return true;
280→}
281→
282→function buildIssueBody(
283→  description: string,
284→  userAgent: string,
285→  pageUrl: string,
286→  imageUrls: string[]
287→): string {
288→  let body = description;
289→
290→  if (imageUrls.length > 0) {
291→    body += "\n\n### Anexos\n\n";
292→    imageUrls.forEach((url, index) => {
293→      body += `![anexo-${index + 1}](${url})\n\n`;
294→    });
295→  }
296→
297→  body += "\n\n---\n\n";
298→  body += `**Página:** ${pageUrl}\n`;
299→  body += `**User Agent:** ${userAgent}\n`;
300→  body += `**Reportado via:** MyPocket Bug Report\n`;
301→
302→  return body;
303→}
304→
305→export async function POST(request: NextRequest) {
306→  try {
307→    const userId = await getAuthenticatedUserId();
308→
309→    const token = getGitHubToken();
310→    if (!token) {
311→      return NextResponse.json(
312→        { error: "Configuração do GitHub não encontrada." },
313→        { status: 500 }
314→      );
315→    }
316→
317→    const formData = await request.formData();
318→    const title = formData.get("title") as string | null;
319→    const description = formData.get("description") as string | null;
320→    const userAgent = (formData.get("userAgent") as string) || "Unknown";
321→    const pageUrl = (formData.get("pageUrl") as string) || "Unknown";
322→
323→    if (!title?.trim() || !description?.trim()) {
324→      return NextResponse.json(
325→        { error: "Título e descrição são obrigatórios." },
326→        { status: 400 }
327→      );
328→    }
329→
330→    // Process images
331→    const imageUrls: string[] = [];
332→    const imageEntries = formData.getAll("images");
333→
334→    if (imageEntries.length > MAX_IMAGES) {
335→      return NextResponse.json(
336→        { error: `Máximo de ${MAX_IMAGES} imagens permitidas.` },
337→        { status: 400 }
338→      );
339→    }
340→
341→    for (const entry of imageEntries) {
342→      if (!isFileLike(entry) || entry.size === 0) continue;
343→
344→      if (!ALLOWED_IMAGE_TYPES.includes(entry.type)) {
345→        return NextResponse.json(
346→          { error: `Tipo de arquivo não suportado: ${entry.type}. Use PNG, JPG ou GIF.` },
347→          { status: 400 }
348→        );
349→      }
350→
351→      if (entry.size > MAX_IMAGE_SIZE) {
352→        return NextResponse.json(
353→          { error: `Imagem "${entry.name}" excede o limite de 5MB.` },
354→          { status: 400 }
355→        );
356→      }
357→
358→      const buffer = Buffer.from(await entry.arrayBuffer());
359→      const base64 = buffer.toString("base64");
360→      const ext = entry.name.split(".").pop() || "png";
361→      const sanitizedName = `${imageUrls.length}.${ext}`;
362→
363→      const downloadUrl = await uploadImageToGitHub(token, base64, sanitizedName);
364→      imageUrls.push(downloadUrl);
365→    }
366→
367→    // Create issue
368→    const body = buildIssueBody(description.trim(), userAgent, pageUrl, imageUrls);
369→    const issue = await createGitHubIssue(token, title.trim(), body);
370→
371→    // Add to project board (best-effort — don't fail the request if this fails)
372→    let projectLinked = false;
373→    try {
374→      projectLinked = await addIssueToProject(token, issue.node_id);
375→    } catch (projectError) {
376→      console.error("Failed to add issue to project board:", projectError);
377→    }
378→
379→    return NextResponse.json({
380→      success: true,
381→      issueNumber: issue.number,
382→      issueUrl: issue.html_url,
383→      projectLinked,
384→    });
385→  } catch (error) {
386→    if (error instanceof Error && error.message === "Unauthorized") {
387→      return unauthorizedResponse();
388→    }
389→    console.error("Bug report error:", error);
390→    return NextResponse.json(
391→      { error: "Erro ao enviar o bug report. Tente novamente." },
392→      { status: 500 }
393→    );
394→  }
