166→function buildIssueBody(
167→  description: string,
168→  userAgent: string,
169→  pageUrl: string,
170→  imageUrls: string[]
171→): string {
172→  let body = description;
173→
174→  if (imageUrls.length > 0) {
175→    body += "\n\n### Anexos\n\n";
176→    imageUrls.forEach((url, index) => {
177→      body += `![anexo-${index + 1}](${url})\n\n`;
178→    });
179→  }
180→
181→  body += "\n\n---\n\n";
182→  body += `**Página:** ${pageUrl}\n`;
183→  body += `**User Agent:** ${userAgent}\n`;
184→  body += `**Reportado via:** MyPocket Bug Report\n`;
185→
186→  return body;
187→}
