 19→interface BugReportModalProps {
 20→  isOpen: boolean;
 21→  onClose: () => void;
 22→}
 23→
 24→interface ImagePreview {
 25→  file: File;
 26→  previewUrl: string;
 27→}
 28→
 29→const MAX_IMAGES = 3;
 30→const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB
 31→const ALLOWED_TYPES = ["image/png", "image/jpeg", "image/gif"];
 32→
 33→export function BugReportModal({ isOpen, onClose }: BugReportModalProps) {
 34→  const { toast } = useToast();
 35→  const [title, setTitle] = useState("");
 36→  const [description, setDescription] = useState("");
 37→  const [images, setImages] = useState<ImagePreview[]>([]);
 38→  const [loading, setLoading] = useState(false);
 39→  const [isDragOver, setIsDragOver] = useState(false);
 40→  const fileInputRef = useRef<HTMLInputElement>(null);
 41→
 42→  // Reset form when modal opens
 43→  useEffect(() => {
 44→    if (isOpen) {
 45→      setTitle("");
 46→      setDescription("");
 47→      setImages([]);
 48→      setLoading(false);
 49→      setIsDragOver(false);
 50→    }
 51→  }, [isOpen]);
 52→
 53→  // Cleanup preview URLs on unmount
 54→  useEffect(() => {
 55→    return () => {
 56→      images.forEach((img) => URL.revokeObjectURL(img.previewUrl));
 57→    };
 58→  }, [images]);
 59→
 60→  function validateAndAddFiles(files: FileList | File[]) {
 61→    const fileArray = Array.from(files);
 62→
 63→    for (const file of fileArray) {
 64→      if (images.length >= MAX_IMAGES) {
 65→        toast({
 66→          title: "Limite de imagens",
 67→          description: `Máximo de ${MAX_IMAGES} imagens permitidas.`,
 68→          variant: "destructive",
 69→        });
 70→        break;
 71→      }
 72→
 73→      if (!ALLOWED_TYPES.includes(file.type)) {
 74→        toast({
 75→          title: "Tipo não suportado",
 76→          description: `Use PNG, JPG ou GIF. Arquivo "${file.name}" ignorado.`,
 77→          variant: "destructive",
 78→        });
 79→        continue;
 80→      }
 81→
 82→      if (file.size > MAX_IMAGE_SIZE) {
 83→        toast({
 84→          title: "Arquivo muito grande",
 85→          description: `"${file.name}" excede o limite de 5MB.`,
 86→          variant: "destructive",
 87→        });
 88→        continue;
 89→      }
 90→
 91→      const previewUrl = URL.createObjectURL(file);
 92→      setImages((prev) => [...prev, { file, previewUrl }]);
 93→    }
 94→  }
 95→
 96→  function removeImage(index: number) {
 97→    setImages((prev) => {
 98→      URL.revokeObjectURL(prev[index].previewUrl);
 99→      return prev.filter((_, i) => i !== index);
100→    });
101→  }
102→
103→  function handleDragOver(e: React.DragEvent) {
104→    e.preventDefault();
105→    setIsDragOver(true);
106→  }
107→
108→  function handleDragLeave(e: React.DragEvent) {
109→    e.preventDefault();
110→    setIsDragOver(false);
111→  }
112→
113→  function handleDrop(e: React.DragEvent) {
114→    e.preventDefault();
115→    setIsDragOver(false);
116→    if (e.dataTransfer.files.length > 0) {
117→      validateAndAddFiles(e.dataTransfer.files);
118→    }
119→  }
120→
121→  async function handleSubmit(e: React.FormEvent) {
122→    e.preventDefault();
123→
124→    if (!title.trim() || !description.trim()) {
125→      toast({
126→        title: "Campos obrigatórios",
127→        description: "Preencha o título e a descrição.",
128→        variant: "destructive",
129→      });
130→      return;
131→    }
132→
133→    setLoading(true);
134→
135→    try {
136→      const formData = new FormData();
137→      formData.append("title", title.trim());
138→      formData.append("description", description.trim());
139→      formData.append("userAgent", navigator.userAgent);
140→      formData.append("pageUrl", window.location.pathname);
141→
142→      for (const img of images) {
143→        formData.append("images", img.file);
144→      }
145→
146→      const response = await fetch("/api/bug-reports", {
147→        method: "POST",
148→        body: formData,
149→      });
150→
151→      if (!response.ok) {
152→        const data = await response.json().catch(() => ({}));
153→        throw new Error(data.error || "Erro ao enviar bug report.");
154→      }
155→
156→      toast({
157→        title: "Bug reportado com sucesso!",
158→        description: "Obrigado pelo feedback. Vamos analisar o problema.",
159→      });
160→
161→      onClose();
162→    } catch (error) {
163→      toast({
164→        title: "Erro ao enviar",
165→        description:
166→          error instanceof Error
167→            ? error.message
168→            : "Não foi possível enviar o bug report. Tente novamente.",
169→        variant: "destructive",
170→      });
171→    } finally {
172→      setLoading(false);
173→    }
174→  }
175→
176→  function handleOpenChange(open: boolean) {
177→    if (!open) onClose();
178→  }
179→
180→  return (
181→    <Dialog open={isOpen} onOpenChange={handleOpenChange}>
182→      <DialogContent className="sm:max-w-[500px]">
183→        <DialogHeader>
184→          <DialogTitle>Reportar Bug</DialogTitle>
185→          <DialogDescription>
186→            Descreva o problema encontrado. Sua mensagem será enviada para análise.
187→          </DialogDescription>
188→        </DialogHeader>
189→
190→        <form onSubmit={handleSubmit} className="space-y-4">
191→          <div className="space-y-2">
192→            <Label htmlFor="bug-title">Título</Label>
193→            <Input
194→              id="bug-title"
195→              placeholder="Resumo do problema"
196→              value={title}
197→              onChange={(e) => setTitle(e.target.value)}
198→              disabled={loading}
199→            />
200→          </div>
201→
202→          <div className="space-y-2">
203→            <Label htmlFor="bug-description">Descrição</Label>
204→            <Textarea
205→              id="bug-description"
206→              placeholder="Descreva o que aconteceu, o que você esperava e como reproduzir o problema..."
207→              value={description}
208→              onChange={(e) => setDescription(e.target.value)}
209→              disabled={loading}
210→              rows={4}
211→            />
212→          </div>
213→
214→          <div className="space-y-2">
215→            <Label>Anexos (opcional)</Label>
216→            <div
217→              onDragOver={handleDragOver}
