 26→  const response = await fetch(
 27→    `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/contents/${path}`,
 28→    {
 29→      method: "PUT",
 30→      headers: {
 31→        Authorization: `Bearer ${token}`,
