 37→        content: base64Content,
 38→      }),
 39→    }
 40→  );
 41→
 42→  if (!response.ok) {
 43→    const error = await response.json().catch(() => ({}));
 44→    throw new Error(
 45→      `Failed to upload image: ${error.message || response.statusText}`
 46→    );
 47→  }
 48→
 49→  const data = await response.json();
 50→  return data.content.download_url;
 51→}
