189→export async function POST(request: NextRequest) {
190→  try {
191→    const userId = await getAuthenticatedUserId();
192→
193→    const token = getGitHubToken();
194→    if (!token) {
195→      return NextResponse.json(
196→        { error: "Configuração do GitHub não encontrada." },
197→        { status: 500 }
198→      );
199→    }
200→
201→    const formData = await request.formData();
202→    const title = formData.get("title") as string | null;
203→    const description = formData.get("description") as string | null;
204→    const userAgent = (formData.get("userAgent") as string) || "Unknown";
205→    const pageUrl = (formData.get("pageUrl") as string) || "Unknown";
206→
207→    if (!title?.trim() || !description?.trim()) {
208→      return NextResponse.json(
209→        { error: "Título e descrição são obrigatórios." },
210→        { status: 400 }
211→      );
212→    }
213→
214→    // Process images
215→    const imageUrls: string[] = [];
216→    const imageEntries = formData.getAll("images");
217→
218→    if (imageEntries.length > MAX_IMAGES) {
219→      return NextResponse.json(
220→        { error: `Máximo de ${MAX_IMAGES} imagens permitidas.` },
221→        { status: 400 }
222→      );
223→    }
224→
225→    for (const entry of imageEntries) {
226→      if (!isFileLike(entry) || entry.size === 0) continue;
227→
228→      if (!ALLOWED_IMAGE_TYPES.includes(entry.type)) {
229→        return NextResponse.json(
230→          { error: `Tipo de arquivo não suportado: ${entry.type}. Use PNG, JPG ou GIF.` },
231→          { status: 400 }
232→        );
233→      }
234→
235→      if (entry.size > MAX_IMAGE_SIZE) {
236→        return NextResponse.json(
237→          { error: `Imagem "${entry.name}" excede o limite de 5MB.` },
238→          { status: 400 }
239→        );
240→      }
241→
242→      const buffer = Buffer.from(await entry.arrayBuffer());
243→      const base64 = buffer.toString("base64");
244→      const ext = entry.name.split(".").pop() || "png";
245→      const sanitizedName = `${imageUrls.length}.${ext}`;
246→
247→      const downloadUrl = await uploadImageToGitHub(token, base64, sanitizedName);
248→      imageUrls.push(downloadUrl);
249→    }
250→
251→    // Create issue
252→    const body = buildIssueBody(description.trim(), userAgent, pageUrl, imageUrls);
253→    const issue = await createGitHubIssue(token, title.trim(), body);
254→
255→    // Add to project board (best-effort — don't fail the request if this fails)
256→    let projectLinked = false;
257→    try {
258→      projectLinked = await addIssueToProject(token, issue.node_id);
259→    } catch (projectError) {
260→      console.error("Failed to add issue to project board:", projectError);
261→    }
262→
263→    return NextResponse.json({
264→      success: true,
265→      issueNumber: issue.number,
266→      issueUrl: issue.html_url,
267→      projectLinked,
268→    });
269→  } catch (error) {
270→    if (error instanceof Error && error.message === "Unauthorized") {
271→      return unauthorizedResponse();
272→    }
273→    console.error("Bug report error:", error);
274→    return NextResponse.json(
275→      { error: "Erro ao enviar o bug report. Tente novamente." },
276→      { status: 500 }
277→    );
278→  }
279→}
